import { invoke } from "@tauri-apps/api/core";
import { open, save } from "@tauri-apps/plugin-dialog";

import type { Persona, PersonaDraft } from "../db/repositories/personasRepo";

/** Our internal persona card format — stores structured fields in `extensions`
 *  while also providing a `description` for SillyTavern compatibility. */
interface PersonaCard {
  spec: "persona_card_v1";
  spec_version: "1.0";
  data: {
    name: string;
    description: string;
    gender: string;
    age: number | null;
    race: string;
    appearance: string;
    skills: { name: string; level: number }[];
    inventory: { item: string; qty: number; note?: string }[];
    /** Raw extensions object from original card (preserved for round-trip) */
    extensions: Record<string, unknown>;
  };
}

function personaToCard(persona: Persona): PersonaCard {
  return {
    spec: "persona_card_v1",
    spec_version: "1.0",
    data: {
      name: persona.name,
      description: persona.description,
      gender: persona.gender,
      age: persona.age,
      race: persona.race,
      appearance: persona.appearance,
      skills: persona.skills,
      inventory: persona.inventory,
      extensions: {},
    },
  };
}

function cardToDraft(card: PersonaCard): PersonaDraft {
  return {
    name: card.data.name,
    gender: card.data.gender,
    age: card.data.age,
    race: card.data.race,
    appearance: card.data.appearance,
    skills: card.data.skills ?? [],
    inventory: card.data.inventory ?? [],
    avatarPath: null,
  };
}

/** Serialises a persona to a JSON card string. */
export function personaToCardJson(persona: Persona): string {
  return JSON.stringify(personaToCard(persona), null, 2);
}

/** Parses a persona card JSON string and returns a draft ready for creation. */
export function cardJsonToDraft(json: string): PersonaDraft {
  const card = JSON.parse(json) as PersonaCard;
  // Handle SillyTavern-style personas (just name+description) by synthesising
  // structured fields from the description.
  if (!card.data.gender && !card.data.appearance && card.data.description) {
    return {
      name: card.data.name,
      gender: "",
      age: null,
      race: "",
      appearance: card.data.description,
      skills: [],
      inventory: [],
      avatarPath: null,
    };
  }
  return cardToDraft(card);
}

/** Opens a native save dialog and exports the persona as a JSON file. */
export async function pickAndExportPersona(persona: Persona): Promise<string | null> {
  const outPath = await save({
    defaultPath: `${persona.name.replace(/[/\\?%*:|"<>]/g, "_")}.persona.json`,
    filters: [{ name: "Persona (JSON)", extensions: ["json"] }],
  });
  if (!outPath) return null;
  await invoke("write_text_file", { path: outPath, content: personaToCardJson(persona) });
  return outPath;
}

/** Opens a native save dialog and exports the persona as a PNG card
 *  (same format as character cards, for SillyTavern compatibility). */
export async function pickAndExportPersonaAsPng(persona: Persona): Promise<string | null> {
  const outPath = await save({
    defaultPath: `${persona.name.replace(/[/\\?%*:|"<>]/g, "_")}.png`,
    filters: [{ name: "PNG", extensions: ["png"] }],
  });
  if (!outPath) return null;

  // Build a character-card-style JSON (ST understands this)
  const stCard = {
    spec: "chara_card_v2",
    spec_version: "2.0",
    data: {
      name: persona.name,
      description: persona.description,
      extensions: {
        persona_v1: {
          gender: persona.gender,
          age: persona.age,
          race: persona.race,
          appearance: persona.appearance,
          skills: persona.skills,
          inventory: persona.inventory,
        },
      },
      // ST-compatible fields (minimal — persona isn't a character)
      personality: "",
      scenario: "",
      first_mes: "",
      mes_example: "",
      system_prompt: "",
      post_history_instructions: "",
      creator_notes: "",
      tags: [],
    },
  };

  const cardJson = JSON.stringify(stCard);
  const avatarPath = persona.avatarPath ?? (await invoke<string>("ensure_placeholder_avatar"));
  await invoke("export_card_png", { cardJson, avatarPath, outPath });
  return outPath;
}

/** Opens a native open dialog and imports a persona from a JSON file.
 *  Returns the draft or null if cancelled. */
export async function pickAndImportPersona(): Promise<PersonaDraft | null> {
  const path = await open({
    multiple: false,
    filters: [{ name: "Persona (JSON)", extensions: ["json"] }],
  });
  if (!path || Array.isArray(path)) return null;
  const content = await invoke<string>("read_text_file", { path: path as string });
  return cardJsonToDraft(content);
}

/** Opens a native open dialog and imports a persona from a PNG card.
 *  Returns the draft or null if cancelled. */
export async function pickAndImportPersonaFromPng(): Promise<PersonaDraft | null> {
  const path = await open({
    multiple: false,
    filters: [{ name: "PNG", extensions: ["png"] }],
  });
  if (!path || Array.isArray(path)) return null;
  const result = await invoke<{ card_json: string }>("import_card_png", { path: path as string });
  const card = JSON.parse(result.card_json);
  const data = card.data ?? card;

  // Try our v1 persona extension first
  const ext = data.extensions?.persona_v1;
  if (ext) {
    return {
      name: data.name ?? ext.name ?? "",
      gender: ext.gender ?? "",
      age: ext.age ?? null,
      race: ext.race ?? "",
      appearance: ext.appearance ?? "",
      skills: ext.skills ?? [],
      inventory: ext.inventory ?? [],
      avatarPath: null,
    };
  }

  // Fallback: SillyTavern persona (name + description only)
  return {
    name: data.name ?? "",
    gender: "",
    age: null,
    race: "",
    appearance: data.description ?? "",
    skills: [],
    inventory: [],
    avatarPath: null,
  };
}

import type { Persona } from "../db/repositories/personasRepo";
import { updatePersona, updatePersonaXpLevel } from "../db/repositories/personasRepo";
import { parseGameTags } from "./inventoryTags";

/** Parses game tags (inventory + skill + level) from the AI response,
 *  updates the persona in DB, and returns the cleaned text. */
export async function processGameResponse(
  persona: Persona | null,
  text: string,
): Promise<string> {
  if (!persona) return text;
  const { cleanText, mutations, skillChanges, levelChanges } = parseGameTags(text);
  if (mutations.length === 0 && skillChanges.length === 0 && levelChanges.length === 0) return text;

  // Apply inventory mutations
  const inv = persona.inventory ? [...persona.inventory.map((i) => ({ ...i }))] : [];
  for (const m of mutations) {
    const existing = inv.find((i) => i.item.toLowerCase() === m.item.toLowerCase());
    if (m.op === "add") {
      if (existing) {
        existing.qty += m.qty;
      } else {
        inv.push({ item: m.item, qty: m.qty });
      }
    } else {
      if (existing) {
        existing.qty -= m.qty;
        if (existing.qty <= 0) inv.splice(inv.indexOf(existing), 1);
      }
    }
  }

  // Apply skill mutations
  const skills = persona.skills ? [...persona.skills.map((s) => ({ ...s }))] : [];
  for (const s of skillChanges) {
    const existing = skills.find((sk) => sk.name.toLowerCase() === s.name.toLowerCase());
    if (s.absolute !== null) {
      // Absolute set: [SKILL:+name:3]
      if (existing) {
        existing.level = s.absolute;
      } else {
        skills.push({ name: s.name, level: s.absolute });
      }
    } else if (s.delta > 0) {
      // Relative increase: [SKILL:name+2] or [SKILL:+name]
      if (existing) {
        existing.level += s.delta;
      } else {
        skills.push({ name: s.name, level: s.delta });
      }
    } else {
      // Decrease: [SKILL:name-1] — remove if <= 0
      if (existing) {
        existing.level = Math.max(0, existing.level + s.delta);
        if (existing.level <= 0) skills.splice(skills.indexOf(existing), 1);
      }
    }
  }

  // Apply level mutations
  let xp = persona.xp ?? 0;
  let level = persona.level ?? 1;
  let hasLevelChanges = false;
  for (const lc of levelChanges) {
    if (lc.xpDelta > 0) { xp += lc.xpDelta; hasLevelChanges = true; }
    if (lc.levelDelta > 0) { level += lc.levelDelta; hasLevelChanges = true; }
  }

  try {
    await updatePersona(persona.id, {
      name: persona.name,
      gender: persona.gender,
      age: persona.age,
      race: persona.race,
      appearance: persona.appearance,
      progression: persona.progression,
      skills,
      inventory: inv,
    });
    if (hasLevelChanges) {
      await updatePersonaXpLevel(persona.id, xp, level);
    }
  } catch {
    // Non-critical
  }

  return cleanText;
}

/**
 * Parses game tags from AI responses — inventory mutations, skill changes,
 * and level progression tags.
 * 
 * Inventory tags:
 *   [INV:+item_name]              — add item (qty 1)
 *   [INV:-item_name]              — remove item
 *   [INV:+n:item_name]            — add n items
 *   [INV:-n:item_name]            — remove n items
 * 
 * Skill tags:
 *   [SKILL:+name]                 — learn new skill (level 1)
 *   [SKILL:+name:level]           — learn skill at given level
 *   [SKILL:name+n]                — increase skill by n levels
 *   [SKILL:name-n]                — decrease skill by n levels
 * 
 * Level tags:
 *   [LEVEL:+xp]                   — add XP (e.g. [LEVEL:+50])
 *   [LEVEL:+level]                — increase level by 1 (e.g. [LEVEL:+1])
 * 
 * Returns the cleaned text (all tags removed) and parsed mutations.
 */
export interface InvMutation {
  op: "add" | "remove";
  item: string;
  qty: number;
}

export interface SkillMutation {
  name: string;
  /** Positive = increase, negative = decrease, 0 = set absolute */
  delta: number;
  absolute: number | null; // used for [SKILL:+name:level]
}

export interface LevelMutation {
  xpDelta: number;
  levelDelta: number;
}

interface ParsedTags {
  cleanText: string;
  mutations: InvMutation[];
  skillChanges: SkillMutation[];
  levelChanges: LevelMutation[];
}

export function parseGameTags(text: string): ParsedTags {
  const mutations: InvMutation[] = [];
  const skillChanges: SkillMutation[] = [];
  const levelChanges: LevelMutation[] = [];

  let cleanText = text;

  // Parse inventory tags: [INV:+/-item]
  cleanText = cleanText.replace(/\[INV:([+-])(\d+:)?([^\]]+)\]/gi, (_m, op: string, qtyPrefix: string | undefined, item: string) => {
    let qty = 1;
    if (qtyPrefix) {
      const n = parseInt(qtyPrefix.replace(":", ""), 10);
      if (!isNaN(n) && n > 0) qty = n;
    }
    mutations.push({ op: op === "+" ? "add" : "remove", item: item.trim(), qty });
    return "";
  });

  // Parse skill tags:
  //   [SKILL:+name] or [SKILL:+name:level]
  //   [SKILL:name+n] or [SKILL:name-n]
  cleanText = cleanText.replace(/\[SKILL:([+-])([^+\-\]:]+)(?::(\d+))?\]/gi, (_m, op: string, name: string, levelStr?: string) => {
    const absolute = levelStr ? parseInt(levelStr, 10) : null;
    skillChanges.push({
      name: name.trim(),
      delta: op === "+" ? 1 : -1,
      absolute,
    });
    return "";
  });

  // Also handle relative: [SKILL:name+n] or [SKILL:name-n]
  cleanText = cleanText.replace(/\[SKILL:([^+\-\]]+)([+-])(\d+)\]/gi, (_m, name: string, op: string, nStr: string) => {
    skillChanges.push({
      name: name.trim(),
      delta: op === "+" ? parseInt(nStr, 10) : -parseInt(nStr, 10),
      absolute: null,
    });
    return "";
  });

  // Parse level tags: [LEVEL:+xp] or [LEVEL:+level]
  cleanText = cleanText.replace(/\[LEVEL:\+(\d+)\]/gi, (_m, nStr: string) => {
    const n = parseInt(nStr, 10);
    if (!isNaN(n) && n > 0) {
      // Heuristic: if the number is small (≤20), treat as level increase;
      // otherwise treat as XP gain. Both can apply simultaneously.
      if (n <= 20) {
        levelChanges.push({ xpDelta: 0, levelDelta: n });
      } else {
        levelChanges.push({ xpDelta: n, levelDelta: 0 });
      }
    }
    return "";
  });

  return { cleanText, mutations, skillChanges, levelChanges };
}

